mapper.select:
SELECT sku.spu_id AS "spuId", min(sku.sale_price_fen) AS "priceFen", CASE WHEN bool_or(sku.inventory_mode = 2) THEN 'in_stock' WHEN coalesce(sum( CASE WHEN sku.inventory_mode = 1 AND warehouse.id IS NOT NULL THEN greatest(stock.on_hand_quantity - stock.reserved_quantity, 0) ELSE 0 END ), 0) > #{lowStockThreshold} THEN 'in_stock' WHEN coalesce(sum( CASE WHEN sku.inventory_mode = 1 AND warehouse.id IS NOT NULL THEN greatest(stock.on_hand_quantity - stock.reserved_quantity, 0) ELSE 0 END ), 0) > 0 THEN 'low_stock' WHEN bool_or(sku.inventory_mode = 1) THEN 'sold_out' ELSE NULL END AS "stock" FROM pinova.product_sku sku LEFT JOIN pinova.inventory_stock stock ON stock.sku_id = sku.id LEFT JOIN pinova.warehouse warehouse ON warehouse.id = stock.warehouse_id AND warehouse.status = 1 AND warehouse.deleted = false WHERE sku.spu_id IN
#{spuId}
AND sku.status = 1 AND sku.deleted = false GROUP BY sku.spu_id
